import { useState } from 'react'

const IN = '#4f46e5'
const IN_BG = '#eef2ff'
const IN_MUTED = '#6366f1'

/**
 * @param {{
 *   summary?: string[],
 *   suggestions?: string[],
 *   generatedAt?: string,
 *   isLoading?: boolean,
 *   variant?: 'dark' | 'light',
 * }} props
 */
export function AiTriageCard({ summary = [], suggestions = [], generatedAt, isLoading = false, variant = 'dark' }) {
  const [hoveredIdx, setHoveredIdx] = useState(null)
  const light = variant === 'light'

  const cardStyle = light
    ? { background: IN_BG, borderColor: '#c7d2fe' }
    : { background: '#0f0f1a', borderColor: '#534AB744' }
  const badgeBg = light ? IN : '#534AB7'
  const titleC = light ? '#312e81' : '#AFA9EC'
  const sectionLabel = light ? IN : '#534AB7'
  const bullet = light ? IN_MUTED : '#7F77DD'
  const textC = light ? '#3730a3' : '#AFA9EC'
  const numBg = light ? '#e0e7ff' : '#534AB722'
  const numFg = light ? IN : '#7F77DD'
  const divider = light ? '#c7d2fe' : '#534AB733'
  const skeleton = light ? '#e2e8f0' : '#1a1a2e'
  const footerC = light ? '#94a3b8' : '#444'

  return (
    <div className="rounded-xl border p-3 flex flex-col gap-3" style={cardStyle}>
      <div className="flex items-center gap-2">
        <span className="text-[10px] font-bold px-1.5 py-0.5 rounded" style={{ background: badgeBg, color: '#fff' }}>
          AI
        </span>
        <span className="text-[12px] font-medium" style={{ color: titleC }}>Instant triage</span>
      </div>

      {isLoading ? (
        <div className="flex flex-col gap-2">
          {[1, 2, 3].map((i) => (
            <div key={i} className="h-3 rounded animate-pulse" style={{ background: skeleton, width: i === 3 ? '60%' : '100%' }} />
          ))}
        </div>
      ) : (
        <>
          {summary.length > 0 && (
            <div className="flex flex-col gap-1.5">
              <span className="text-[10px] font-semibold uppercase tracking-wider" style={{ color: sectionLabel }}>
                Summary
              </span>
              {summary.map((point, i) => (
                <div key={i} className="flex items-start gap-2">
                  <span className="w-1 h-1 rounded-full mt-1.5 shrink-0" style={{ background: bullet }} />
                  <p className="text-[12px] leading-relaxed" style={{ color: textC }}>{point}</p>
                </div>
              ))}
            </div>
          )}

          {suggestions.length > 0 && <div className="border-t" style={{ borderColor: divider }} />}

          {suggestions.length > 0 && (
            <div className="flex flex-col gap-2">
              <span className="text-[10px] font-semibold uppercase tracking-wider" style={{ color: sectionLabel }}>
                Suggested steps
              </span>
              {suggestions.map((step, i) => (
                <div
                  key={i}
                  className="flex items-start gap-2 group relative"
                  onMouseEnter={() => setHoveredIdx(i)}
                  onMouseLeave={() => setHoveredIdx(null)}
                >
                  <span
                    className="w-5 h-5 rounded-full flex items-center justify-center text-[10px] font-bold shrink-0 mt-0.5"
                    style={{ background: numBg, color: numFg }}
                  >
                    {i + 1}
                  </span>
                  <p className="text-[12px] leading-relaxed flex-1" style={{ color: textC }}>{step}</p>
                  {hoveredIdx === i && (
                    <button type="button" className="text-[10px] shrink-0 font-medium" style={{ color: IN }}>
                      Use this →
                    </button>
                  )}
                </div>
              ))}
            </div>
          )}
        </>
      )}

      <p className="text-[10px]" style={{ color: footerC }}>
        Generated by AI{generatedAt ? ` · ${generatedAt}` : ''}
      </p>
    </div>
  )
}
